    "/sites/{siteId}/llmo/probes/edge-optimize": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        /**
         * Edge Optimize connectivity probe — detect WAF/Bot Manager blocking
         * @description Checks whether a WAF or Bot Manager is silently blocking the
         *     `AdobeEdgeOptimize/1.0` user-agent at the customer's origin.
         *
         *     This is the first entry in the **`/llmo/probes/`** namespace.  Each LLMO
         *     feature that depends on origin reachability can expose its own probe
         *     endpoint here.
         *
         *     **How it works**:
         *     The request is proxied through the Optimize at Edge worker
         *     (`live.edgeoptimize.net`), which originates the fetch using the
         *     production `AdobeEdgeOptimize/1.0` user-agent from the same edge IPs
         *     as real optimizer traffic. This is critical because WAFs that combine
         *     UA-matching with IP-reputation (e.g. Akamai BOTMAN) only trigger on
         *     traffic from the optimizer's actual edge IPs.
         *
         *     **Detection logic**:
         *     | Outcome | Condition | Result |
         *     |---------|-----------|--------|
         *     | Hard block | HTTP 401, 403, 406, 429, or 503 | `reachable: false, blocked: true` |
         *     | CF challenge | `cf-mitigated: challenge` header (any status) | `reachable: false, blocked: true` |
         *     | Soft block | 2xx HTML body containing WAF/bot-challenge keywords | `reachable: false, blocked: true` |
         *     | Clean pass | 2xx with real content | `reachable: true, blocked: false` |
         *     | Network/timeout | Fetch fails or times out | `reachable: false, blocked: null` |
         */
        get: operations["probeEdgeOptimizeConnectivity"];
        put?: never;
        post?: never;
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
