    resolveSite: {
        parameters: {
            query?: {
                /** @description UUID of the organization (mutually exclusive with imsOrg) */
                organizationId?: components["schemas"]["Id"];
                /** @description IMS Organization ID (mutually exclusive with organizationId) */
                imsOrg?: components["schemas"]["ImsOrganizationId"];
                /** @description UUID of a specific site to validate against the organization */
                siteId?: components["schemas"]["Id"];
                /**
                 * @description IMS Organization ID of the *caller* (the org their AEC shell is currently in),
                 *     independent of which org's data is being requested via organizationId/imsOrg.
                 *     When provided, it is translated to a Spacecat UUID and used to determine if
                 *     the caller is an internal/demo org listed in `ASO_PLG_EXCLUDED_ORGS`. For
                 *     internal callers, PLG-wizard-triggering resolveStatuses
                 *     (`no_entitlement_for_product`, `aso_pre_onboard`) are remapped to
                 *     `site_not_enrolled` so the UI shows "No site onboarded" instead of the PLG
                 *     onboarding wizard.
                 */
                callerImsOrg?: components["schemas"]["ImsOrganizationId"];
            };
            header?: never;
            path?: never;
            cookie?: never;
        };
        requestBody?: never;
        responses: {
            /** @description Successfully resolved site and organization data */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        data?: {
                            organization?: components["schemas"]["Organization"];
                            site?: components["schemas"]["Site"];
                            /** @description Whether the summit-plg audit is enabled for the resolved site */
                            isSummitPlgEnabled?: boolean;
                        };
                    };
                };
            };
            /** @description Bad request - missing required parameters or invalid input */
            400: {
                headers: {
                    "X-Error": components["headers"]["xError"];
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        message?: string;
                    };
                };
            };
            /**
             * @description Not found - no site could be resolved.
             *
             *     When the failure is reached via the `siteId` resolution path, the body
             *     carries a structured `resolveStatus` discriminator so clients can
             *     distinguish "not enrolled" from "site doesn't exist" without
             *     re-querying entitlements:
             *
             *     - `no_entitlement_for_product` — org has no entitlement for the
             *       resolved product.
             *     - `aso_pre_onboard` — entitlement tier is not in
             *       `CUSTOMER_VISIBLE_TIERS` (e.g. `PRE_ONBOARD`).
             *     - `site_not_enrolled` — entitlement is visible but no `SiteEnrollment`
             *       links the site.
             *
             *     Generic 404s (e.g. site / org not found) omit `resolveStatus` and
             *     `details`.
             */
            404: {
                headers: {
                    "X-Error": components["headers"]["xError"];
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        message?: string;
                        /**
                         * @description Structured resolution status. Present only on the
                         *     `siteId`-resolution path; absent on generic 404s.
                         * @enum {string}
                         */
                        resolveStatus?: "no_entitlement_for_product" | "aso_pre_onboard" | "site_not_enrolled";
                        /**
                         * @description Context for the resolution failure. Always
                         *     `{ productCode, siteId, organizationId }` when
                         *     `resolveStatus` is set (these branches are reached only
                         *     via the `siteId` resolution path).
                         */
                        details?: {
                            /** @example ASO */
                            productCode?: string;
                            siteId?: components["schemas"]["Id"];
                            organizationId?: components["schemas"]["Id"];
                        };
                    };
                };
            };
            /** @description Internal server error */
            500: {
                headers: {
                    "X-Error": components["headers"]["xError"];
                    [name: string]: unknown;
                };
                content?: never;
            };
        };
    };
