    onboardCustomer: {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        requestBody: {
            content: {
                "application/json": {
                    /**
                     * Format: hostname
                     * @description The domain name to onboard (without protocol)
                     * @example example.com
                     */
                    domain: string;
                    /**
                     * @description The brand name for the site
                     * @example Example Brand
                     */
                    brandName: string;
                    /**
                     * @description When true, skips updating helix-query.yaml in the project-elmo-ui-data GitHub repo
                     *     (temporary onboarding; default is false).
                     */
                    "temp-onboarding"?: boolean;
                    /**
                     * @description Optional ISO 3166-1 alpha-2 country code for the brand's primary market.
                     *     Forwarded to DRS prompt generation so the GPT job conditions on the right region.
                     *     If omitted, the DRS client defaults to 'US' (backward-compatible).
                     * @example IN
                     */
                    region?: string;
                };
            };
        };
        responses: {
            /** @description LLMO onboarding initiated successfully */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        /**
                         * @description Success message
                         * @example LLMO onboarding initiated successfully
                         */
                        message: string;
                        /**
                         * Format: hostname
                         * @description The domain name
                         * @example example.com
                         */
                        domain: string;
                        /**
                         * @description The brand name
                         * @example Example Brand
                         */
                        brandName: string;
                        /**
                         * @description The IMS Organization ID
                         * @example 1234567890ABCDEF@AdobeOrg
                         */
                        imsOrgId: string;
                        /**
                         * Format: uuid
                         * @description The organization ID (created or existing)
                         * @example 123e4567-e89b-12d3-a456-426614174000
                         */
                        organizationId?: string;
                        /**
                         * Format: uuid
                         * @description The created or existing site ID
                         * @example 987fcdeb-51a2-43d1-9f12-345678901234
                         */
                        siteId?: string;
                        /**
                         * @description CDN provider detected during onboarding. The enum is the
                         *     canonical `CDN_TYPES` vocabulary shared with the radio
                         *     selector UI (see
                         *     `src/controllers/llmo/llmo-utils.js#CDN_TYPES`), so the
                         *     value can drive the UI auto-select directly.
                         *
                         *     Emitted by the detector today (7 of the 10 tokens):
                         *       - `aem-cs-fastly` / `commerce-fastly` — Adobe-managed
                         *         CDNs identified by the DNS fast-path.
                         *       - `byocdn-fastly` / `byocdn-akamai` /
                         *         `byocdn-cloudflare` / `byocdn-imperva` — direct
                         *         BYOCDN matches from the multi-signal probe (HTTP
                         *         headers, CNAME chain, ASN, PTR).
                         *       - `byocdn-other` — catch-all. Emitted when Phase 1 +
                         *         Phase 2 both run cleanly and no specific signature
                         *         matches, OR when the probe identifies a third-party
                         *         CDN (CloudFront, Azure Front Door / Azure CDN,
                         *         Vercel, Netlify, Bunny, Sucuri, Alibaba, etc.) that
                         *         LLMO does not model as a first-class BYOCDN.
                         *         CloudFront and Azure Front Door land here today
                         *         because the detector cannot disambiguate AMS vs BYO
                         *         tenancy from network signals alone.
                         *
                         *     Reserved for future detector revisions (not emitted
                         *     today):
                         *       - `byocdn-cloudfront`, `ams-cloudfront`,
                         *         `ams-frontdoor` — will replace the `byocdn-other`
                         *         collapse above once AMS-aware signatures ship;
                         *         listed here so consumers don't need a schema bump
                         *         at that point.
                         *
                         *     `null` — at least one probe was inconclusive (DNS or
                         *     HTTP failure), so the UI auto-select stays neutral.
                         * @example aem-cs-fastly
                         * @enum {string|null}
                         */
                        detectedCdn?: "aem-cs-fastly" | "commerce-fastly" | "byocdn-fastly" | "byocdn-akamai" | "byocdn-cloudfront" | "byocdn-cloudflare" | "byocdn-imperva" | "byocdn-other" | "ams-cloudfront" | "ams-frontdoor" | null;
                        /**
                         * @description The onboarding status
                         * @example initiated
                         * @enum {string}
                         */
                        status: "initiated" | "in_progress" | "completed" | "failed";
                        /**
                         * Format: date-time
                         * @description The timestamp when onboarding was initiated
                         * @example 2025-01-15T10:30:00Z
                         */
                        createdAt?: string;
                        /**
                         * @description Echo of the ISO 3166-1 alpha-2 region code accepted by the
                         *     server. Present only when the caller supplied `region` in
                         *     the request body; omitted when the DRS default ('US')
                         *     applies.
                         * @example IN
                         */
                        region?: string;
                    };
                };
            };
            400: components["responses"]["400"];
            401: components["responses"]["401"];
            403: components["responses"]["403"];
            500: components["responses"]["500"];
        };
    };
